const updateType = $json.message ? 'message' : ($json.callback_query ? 'callback_query' : 'unknown');
let telegram_id, chat_id, text, callback_data;

if (updateType === 'message') {
  telegram_id = $json.message.from.id;
  chat_id = $json.message.chat.id;
  text = $json.message.text ? $json.message.text.trim() : '';
  } 
    else if (updateType === 'callback_query') {
    telegram_id = $json.callback_query.from.id;
    chat_id = $json.callback_query.message.chat.id;
    callback_data = $json.callback_query.data;
  }

return [{
  updateType,
  telegram_id,
  chat_id,
  text,
  callback_data,
  raw_payload: $json
}];

let text = '📦 *Daftar Stok Gudang (Page 1)*\n\n```\n';
text += 'No | Kode Barang  | Nama Barang         | Qty\n';
text += '---+--------------+---------------------+-----\n';
if ($input.all().length === 0 || !$input.all()[0].json.item_code) {
  text = '⚠️ Gudang kosong.';
} else {
  let num = 1;
  for (const item of $input.all()) {
    let id = num.toString().padEnd(2, ' ');
    let code = (item.json.item_code || '-').substring(0, 12).padEnd(12, ' ');
    let name = (item.json.name_item || '-').substring(0, 19).padEnd(19, ' ');
    let qty = (item.json.quantity || 0).toString().padStart(4, ' ');

    text += `${id} | ${code} | ${name} | ${qty}\n`;
    num++;
  }
  text += '```';
}

