const text = $node["Normalize Payload"].json.text;
const parts = text.split(/\s+/);
if (parts.length < 5) {
  return [{ error: true, msg: 'Format salah. Pastikan memisahkan data dengan spasi sesuai contoh.' }];
}

return [{
  error: false,
  item_code: parts[0],
  kode_barang: parts[1],
  name_item: parts.slice(2, parts.length - 2).join(' '),
  qty: parts[parts.length - 2],
  min_threshold: parts[parts.length - 1]
}];

